// Bicep: resource type is part of the resource declaration
// Format: '{namespace}/{type}@{api-version}'

resource vm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'myvm'
  location: resourceGroup().location
  properties: {
    hardwareProfile: { vmSize: 'Standard_D2s_v5' }
    // ...
  }
}

// Child resource type: append the child type after the parent type
resource vmExtension 'Microsoft.Compute/virtualMachines/extensions@2023-03-01' = {
  parent: vm  // links to the parent VM
  name: 'AzureMonitorLinuxAgent'
  location: resourceGroup().location
  properties: {
    publisher: 'Microsoft.Azure.Monitor'
    type: 'AzureMonitorLinuxAgent'
    typeHandlerVersion: '1.0'
    autoUpgradeMinorVersion: true
  }
}

// Reference a resource type's api-version without deploying it
var storageApiVersion = '2023-01-01'
resource existingStorage 'Microsoft.Storage/storageAccounts@2023-01-01' existing = {
  name: 'mystorageacct'
}

# Terraform: resource type is embedded in the resource block label
# azurerm_{service}_{resource_type}

resource "azurerm_virtual_machine" "myvm" {
  name                = "myvm"
  resource_group_name = azurerm_resource_group.myapp.name
  location            = azurerm_resource_group.myapp.location
  vm_size             = "Standard_D2s_v5"
  # ...
}

# Terraform uses the latest stable API version by default
# To use a preview API feature, use azapi provider instead:
resource "azapi_resource" "vm_preview" {
  type      = "Microsoft.Compute/virtualMachines@2023-09-01-preview"
  name      = "myvm-preview"
  parent_id = azurerm_resource_group.myapp.id
  location  = azurerm_resource_group.myapp.location
  body = jsonencode({
    properties = {
      # preview-only property
      hibernationProfile = { hibernationEnabled = true }
    }
  })
}

# Azure Policy: target resources by resource type
# The 'type' field in policy conditions uses the fully-qualified type

# Policy rule that applies only to VMs
POLICY_RULE='{
  "if": {
    "field": "type",
    "equals": "Microsoft.Compute/virtualMachines"
  },
  "then": {
    "effect": "auditIfNotExists",
    "details": {
      "type": "Microsoft.Compute/virtualMachines/extensions",
      "existenceCondition": {
        "field": "Microsoft.Compute/virtualMachines/extensions/type",
        "equals": "AzureMonitorLinuxAgent"
      }
    }
  }
}'

# List built-in policies that target a specific resource type
az policy definition list \
  --query "[?policyRule.if.field=='type' && policyRule.if.equals=='Microsoft.Compute/virtualMachines']
           .{name:name, displayName:displayName}" \
  -o table

// ARM template: resource type appears in both 'type' and 'apiVersion' fields
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "resources": [
    {
      "type": "Microsoft.Storage/storageAccounts",
      "apiVersion": "2023-01-01",
      "name": "mystorageacct",
      "location": "[resourceGroup().location]",
      "sku": { "name": "Standard_LRS" },
      "kind": "StorageV2",
      "properties": {
        "minimumTlsVersion": "TLS1_2",
        "allowBlobPublicAccess": false
      }
    },
    {
      "type": "Microsoft.Storage/storageAccounts/blobServices/containers",
      "apiVersion": "2023-01-01",
      "name": "[concat('mystorageacct/default/mycontainer')]",
      "dependsOn": ["[resourceId('Microsoft.Storage/storageAccounts', 'mystorageacct')]"],
      "properties": { "publicAccess": "None" }
    }
  ]
}

# Azure Policy: target resources by resource type
# The 'type' field in policy conditions uses the fully-qualified type

# Policy rule that applies only to VMs
POLICY_RULE='{
  "if": {
    "field": "type",
    "equals": "Microsoft.Compute/virtualMachines"
  },
  "then": {
    "effect": "auditIfNotExists",
    "details": {
      "type": "Microsoft.Compute/virtualMachines/extensions",
      "existenceCondition": {
        "field": "Microsoft.Compute/virtualMachines/extensions/type",
        "equals": "AzureMonitorLinuxAgent"
      }
    }
  }
}'

# List built-in policies that target a specific resource type
az policy definition list \
  --query "[?policyRule.if.field=='type' && policyRule.if.equals=='Microsoft.Compute/virtualMachines']
           .{name:name, displayName:displayName}" \
  -o table

